import { forwardRef, useImperativeHandle, useRef } from 'react';
import { Button, ButtonProps } from '@ui/components/Button/Button';
import {
  IRichTextEditorProps,
  IRichTextEditorRef,
  RichTextEditor,
} from '@ui/components/molecules/RichTextEditor';
import { Label } from '@ui/components/typography';

export interface IRichTextEditorControlProps extends IRichTextEditorProps {
  description?: string;
  name: string;
  replacementActionText?: string;
  replacementActionTextProps?: ButtonProps;
  replacementText?: string;
}

export type RichTextEditorControlMethods = { replaceText: (text: string) => void };

export const RichTextEditorControl = forwardRef<
  RichTextEditorControlMethods,
  IRichTextEditorControlProps
>(
  (
    { description, replacementActionText, replacementActionTextProps, replacementText, ...props },
    imperativeRef
  ) => {
    const ref = useRef<IRichTextEditorRef>(null);

    const replaceText = () => {
      if (!replacementText) {
        return;
      }
      ref.current?.replaceText(replacementText);
    };

    useImperativeHandle(
      imperativeRef,
      () => {
        return {
          replaceText(text: string) {
            ref.current?.replaceText(text);
          },
        };
      },
      []
    );

    return (
      <>
        {description && (
          <Label pb="16px" textAlign="left">
            {description}
          </Label>
        )}
        {replacementText && replacementActionText && (
          <Button
            display="inline-block"
            marginBottom={6}
            onClick={replaceText}
            textDecoration="none"
            variant="link"
            {...replacementActionTextProps}
          >
            {replacementActionText}
          </Button>
        )}
        <RichTextEditor {...props} ref={ref} />
      </>
    );
  }
);
