import { usePreConversionUpsellActions } from '../hooks';

type Props = {
  formKey:
    | 'preConversionUpsellBody'
    | 'preConversionUpsellAcceptAction'
    | 'preConversionUpsellDeclineAction';
  theme: CommonDesignOptions;
};

export const BlockPreview = ({ formKey, theme }: Props) => {
  const { isOpen, onClose, onOpen } = useEditorBlock();
  const preConversionUpsellMethods = usePreConversionUpsellActions({ onClose });

  let preview = null;
  let editor = null;

  switch (formKey) {
    case 'preConversionUpsellBody':
      editor = <PreConversionUpsellBodyEditor formKey={formKey} {...preConversionUpsellMethods} />;
      preview = <PreConversionUpsellBodyPreview formKey={formKey} />;
      break;
    case 'preConversionUpsellAcceptAction':
      editor = (
        <PreConversionUpsellActionButtonEditor formKey={formKey} {...preConversionUpsellMethods} />
      );
      preview = <PreConversionUpsellActionButtonPreview formKey={formKey} theme={theme} />;
      break;
    case 'preConversionUpsellDeclineAction':
      editor = (
        <PreConversionUpsellActionButtonEditor formKey={formKey} {...preConversionUpsellMethods} />
      );
      preview = <PreConversionUpsellActionButtonPreview formKey={formKey} theme={theme} />;
      break;
    default:
      throw new Error('Unknown content block type');
  }

  return (
    <Box>
      <HighlightPopover
        content={editor}
        isOpen={isOpen}
        onClose={onClose}
        onOpen={onOpen}
        trigger={preview}
      />
    </Box>
  );
};
